export function formatPrice(n) {
  if (n >= 10000) return '$' + n.toLocaleString('tr-TR', { maximumFractionDigits: 0 });
  if (n >= 1)     return '$' + n.toFixed(2);
  return '$' + n.toFixed(4);
}

export function rnd(min, max) {
  return Math.random() * (max - min) + min;
}

export function generatePriceData(basePrice, count = 60) {
  const data = [];
  let price = basePrice * (1 + (Math.random() - 0.5) * 0.05);
  for (let i = 0; i < count; i++) {
    price *= 1 + (Math.random() - 0.495) * 0.018;
    data.push(parseFloat(price.toFixed(6)));
  }
  return data;
}

export function generateTimeLabels(count = 60, intervalMinutes = 60) {
  const labels = [];
  const now = Date.now();
  for (let i = count - 1; i >= 0; i--) {
    const d = new Date(now - i * intervalMinutes * 60000);
    labels.push(
      d.getHours().toString().padStart(2, '0') + ':' +
      d.getMinutes().toString().padStart(2, '0')
    );
  }
  return labels;
}

export function calculateIndicators(prices) {
  const last = prices[prices.length - 1];
  const prev = prices[prices.length - 10] || last;
  return {
    rsi:      Math.round(rnd(22, 78)),
    macd:     parseFloat((last - prev).toFixed(2)),
    emaCross: Math.random() > 0.5,
    bbPos:    parseFloat(rnd(5, 95).toFixed(1)),
    volume:   rnd(100, 999).toFixed(0) + 'M',
  };
}

export function generateSignal(indicators, botId) {
  const { rsi, macd, emaCross, bbPos } = indicators;
  let score = 0;
  if (rsi < 38)   score += 2;
  if (rsi > 62)   score -= 2;
  if (macd > 0)   score += 2; else score -= 2;
  if (emaCross)   score += 2; else score -= 2;
  if (bbPos < 25) score += 1;
  if (bbPos > 75) score -= 1;
  if (botId === 'hybrid') score += 1;

  if (score >= 3) return {
    type: 'AL', icon: '🚀', cls: 'buy', score,
    reason: `RSI aşırı satım bölgesine yakın (${rsi}), MACD pozitif ve ${emaCross ? 'EMA Golden Cross oluştu' : 'trend yukarı'}. Alım fırsatı olabilir.`
  };
  if (score <= -3) return {
    type: 'SAT', icon: '🔻', cls: 'sell', score,
    reason: `RSI yüksek (${rsi}), MACD negatif ve Bollinger üst bandına yaklaşıldı (%${bbPos}). Kâr realizasyonu değerlendirilebilir.`
  };
  return {
    type: 'BEKLE', icon: '⏸', cls: 'hold', score,
    reason: `Göstergeler net sinyal vermiyor. RSI: ${rsi}, MACD: ${macd > 0 ? 'pozitif' : 'negatif'}. Daha güçlü kurulum bekleniyor.`
  };
}
